def evalInput(inputStr):
    # Define safe operations
    safe_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    # Define safe functions
    safe_functions = {
        'abs': abs, 'all': all, 'any': any, 'bin': bin, 'bool': bool,
        'chr': chr, 'divmod': divmod, 'enumerate': enumerate, 'filter': filter,
        'float': float, 'hex': hex, 'int': int, 'len': len, 'list': list,
        'map': map, 'max': max, 'min': min, 'oct': oct, 'ord': ord,
        'pow': pow, 'range': range, 'reversed': reversed, 'round': round,
        'sorted': sorted, 'str': str, 'sum': sum, 'tuple': tuple, 'zip': zip,
        'sqrt': math.sqrt, 'sin': math.sin, 'cos': math.cos, 'tan': math.tan,
        'asin': math.asin, 'acos': math.acos, 'atan': math.atan,
        'log': math.log, 'log10': math.log10, 'exp': math.exp,
        'floor': math.floor, 'ceil': math.ceil, 'fabs': math.fabs
    }

    # Define safe constants
    safe_constants = {
        'pi': math.pi,
        'e': math.e
    }

    def safe_eval(node):
        if isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
            return node.n
        elif isinstance(node, ast.Str):  # For Python < 3.8 compatibility
            return node.s
        elif isinstance(node, ast.Name):
            if node.id in safe_constants:
                return safe_constants[node.id]
            else:
                raise ValueError(f"Unsafe name: {node.id}")
        elif isinstance(node, ast.BinOp):
            left = safe_eval(node.left)
            right = safe_eval(node.right)
            if type(node.op) in safe_operators:
                return safe_operators[type(node.op)](left, right)
            else:
                raise ValueError(f"Unsafe operator: {type(node.op)}")
        elif isinstance(node, ast.UnaryOp):
            operand = safe_eval(node.operand)
            if type(node.op) in safe_operators:
                return safe_operators[type(node.op)](operand)
            else:
                raise ValueError(f"Unsafe unary operator: {type(node.op)}")
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in safe_functions:
                args = [safe_eval(arg) for arg in node.args]
                return safe_functions[node.func.id](*args)
            else:
                raise ValueError(f"Unsafe function call")
        elif isinstance(node, ast.List):
            return [safe_eval(item) for item in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(safe_eval(item) for item in node.elts)
        else:
            raise ValueError(f"Unsafe node type: {type(node)}")

    try:
        tree = ast.parse(inputStr, mode='eval')
        return safe_eval(tree.body)
    except:
        return None

